-- ============================================================
-- ATLAS STUDIO — Migration Email
-- Tables : atlas_email_config + atlas_email_templates
-- ============================================================

-- Table config par tenant (domaine custom, SPF/DKIM)
CREATE TABLE IF NOT EXISTS atlas_email_config (
  id UUID PRIMARY KEY DEFAULT gen_random_uuid(),
  tenant_id UUID REFERENCES tenants(id) ON DELETE CASCADE,
  custom_domain_enabled BOOLEAN DEFAULT FALSE,
  custom_from_email TEXT,
  custom_from_name TEXT,
  spf_verified BOOLEAN DEFAULT FALSE,
  dkim_verified BOOLEAN DEFAULT FALSE,
  created_at TIMESTAMPTZ DEFAULT NOW(),
  updated_at TIMESTAMPTZ DEFAULT NOW(),
  UNIQUE(tenant_id)
);

-- Table templates
CREATE TABLE IF NOT EXISTS atlas_email_templates (
  id UUID PRIMARY KEY DEFAULT gen_random_uuid(),
  app_id TEXT NOT NULL DEFAULT 'core',
  template_key TEXT NOT NULL,
  sender TEXT NOT NULL DEFAULT 'notifications@atlasstudio.org',
  subject TEXT NOT NULL,
  body_html TEXT NOT NULL,
  variables JSONB NOT NULL DEFAULT '[]',
  lang TEXT NOT NULL DEFAULT 'fr',
  is_active BOOLEAN NOT NULL DEFAULT TRUE,
  created_at TIMESTAMPTZ DEFAULT NOW(),
  updated_at TIMESTAMPTZ DEFAULT NOW(),
  UNIQUE(app_id, template_key, lang)
);

-- Index
CREATE INDEX IF NOT EXISTS idx_email_templates_lookup
  ON atlas_email_templates(app_id, template_key, lang);

-- RLS
ALTER TABLE atlas_email_config ENABLE ROW LEVEL SECURITY;
ALTER TABLE atlas_email_templates ENABLE ROW LEVEL SECURITY;

CREATE POLICY "Templates lisibles par service authentifie"
  ON atlas_email_templates FOR SELECT
  USING (true);

CREATE POLICY "Email config par tenant"
  ON atlas_email_config FOR ALL
  USING (tenant_id = auth.uid());

